const stats = .first().json;
const active = .all();

let text = '<b>📊 НОВЕЛЛЫ: ДАШБОРД ПЕРЕВОДА</b>

';
text += '━━━━━━━━━━━━━━━
';
text += '📑 <b>Всего заданий:</b> ' + (stats.total_jobs || 0) + '
';
text += '✅ <b>Завершено:</b> ' + (stats.completed_jobs || 0) + '
';
text += '⏳ <b>В процессе:</b> ' + (stats.active_jobs || 0) + '
';
text += '━━━━━━━━━━━━━━━
';
text += '🧩 <b>Чанков переведено:</b> ' + (stats.total_chunks_translated || 0) + '
';
text += '💰 <b>Neuro billing:</b> $' + (stats.total_neuro || 0) + '
';
text += '💰 <b>Polza billing:</b> $' + (stats.total_polza || 0) + '
';
text += '━━━━━━━━━━━━━━━
';

if (active && active.length > 0) {
  text += '
🔥 <b>АКТИВНЫЕ ЗАДАЧИ:</b>
';
  active.forEach(job => {
    text += '
▶️ <code>' + job.json.file_name + '</code>
';
    const date = job.json.created_at ? new Date(job.json.created_at).toLocaleString('ru-RU') : 'неизвестно';
    text += '   ↳ <i>Старт: ' + date + '</i>
';
  });
} else {
  text += '
🛌 <i>Активных задач нет</i>
';
}

text += '
🕒 <i>Обновлено: ' + new Date().toLocaleString('ru-RU') + '</i>';

return { message: text };
